import{_ as e,o as a,c as r,a2 as n}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"RFC-010 — Translation & Internationalisation Strategy","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-010.md","filePath":"rfc/RFC-010.md"}'),o={name:"rfc/RFC-010.md"};function i(s,t,d,l,c,h){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="rfc-010-—-translation-internationalisation-strategy" tabindex="-1">RFC-010 — Translation &amp; Internationalisation Strategy <a class="header-anchor" href="#rfc-010-—-translation-internationalisation-strategy" aria-label="Permalink to &quot;RFC-010 — Translation &amp; Internationalisation Strategy&quot;">​</a></h1><p><em>Orrery · Closed RFC · v0.1 · May 2026</em></p><blockquote><p><strong>Status:</strong> Closed (2026-05-04) <strong>Author:</strong> product <strong>Closed by:</strong> ADR-031 (language list + waves), ADR-032 (font &amp; script strategy — Wave 1; CJK + RTL deferred), ADR-033 (LLM-only translation workflow) <strong>Slice gate:</strong> v2.0 — i18n architecture already in place per ADR-017; this RFC governed language selection and rollout Why this is an RFC · ADR-017 locked the i18n <em>architecture</em>. Which languages to ship and in what order, how to handle non-Latin scripts (CJK fonts, Arabic RTL, Devanagari), and what translation workflow to adopt are three independent questions with real trade-offs (reach vs implementation cost; bundle-size vs typographic identity; quality vs scalability). Each has multiple defensible answers — hence the RFC.</p></blockquote><hr><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The i18n architecture was established in Slice 6 (v1.0) with the following constraint locked in:</p><blockquote><p><em>&quot;Languages other than English (i18n architecture is in place — add translations without code changes)&quot;</em></p></blockquote><p>This means translation strings are already externalised, locale switching is implemented, and no code changes are required to add a new language — only translation files.</p><p>This RFC governs three open questions that must be resolved before v2.0 work begins:</p><ol><li><strong>Which languages</strong> do we ship, in which order?</li><li><strong>How do we handle non-Latin scripts</strong> (CJK, Arabic RTL, Devanagari)?</li><li><strong>What is the translation workflow</strong> — who translates, how do we QA?</li></ol><hr><h2 id="why-these-languages" tabindex="-1">Why these languages <a class="header-anchor" href="#why-these-languages" aria-label="Permalink to &quot;Why these languages&quot;">​</a></h2><p>The candidate list was derived by unioning two sets:</p><p><strong>Set A — World top 5 languages by total speakers</strong></p><table tabindex="0"><thead><tr><th>Language</th><th>Speakers</th></tr></thead><tbody><tr><td>English</td><td>1.5B (shipped)</td></tr><tr><td>Mandarin Chinese</td><td>1.1B</td></tr><tr><td>Hindi</td><td>600M</td></tr><tr><td>Spanish</td><td>560M</td></tr><tr><td>French</td><td>310M</td></tr></tbody></table><p><strong>Set B — Languages of active space-faring nations</strong></p><p>Agencies with human spaceflight, deep-space missions, or active launch programmes, grouped by tier:</p><table tabindex="0"><thead><tr><th>Tier</th><th>Agency</th><th>Country</th><th>Language</th></tr></thead><tbody><tr><td>1 — Human spaceflight + deep space</td><td>NASA</td><td>USA</td><td>English ✅</td></tr><tr><td>1</td><td>Roscosmos</td><td>Russia</td><td>Russian</td></tr><tr><td>1</td><td>CNSA / CMSA</td><td>China</td><td>Mandarin</td></tr><tr><td>2 — Active launches + deep space</td><td>ISRO</td><td>India</td><td>Hindi</td></tr><tr><td>2</td><td>JAXA</td><td>Japan</td><td>Japanese</td></tr><tr><td>2</td><td>ESA (23 nations)</td><td>Europe</td><td>French, German, Italian, Spanish, Dutch, Portuguese</td></tr><tr><td>2</td><td>CNES</td><td>France</td><td>French</td></tr><tr><td>2</td><td>DLR</td><td>Germany</td><td>German</td></tr><tr><td>2</td><td>ASI</td><td>Italy</td><td>Italian</td></tr><tr><td>3 — Active satellite ops + growing</td><td>UAESA</td><td>UAE</td><td>Arabic</td></tr><tr><td>3</td><td>KARI</td><td>South Korea</td><td>Korean</td></tr><tr><td>3</td><td>AEB</td><td>Brazil</td><td>Portuguese</td></tr><tr><td>3</td><td>CSA</td><td>Canada</td><td>English / French</td></tr><tr><td>3</td><td>UKSA</td><td>UK</td><td>English</td></tr><tr><td>3</td><td>ISA</td><td>Israel</td><td>Hebrew</td></tr><tr><td>3</td><td>ASA</td><td>Australia</td><td>English</td></tr></tbody></table><p>The union of both sets yields the candidate list in §Open Questions below.</p><hr><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><h3 id="oq-1-—-which-languages-ship-in-v2-0-and-in-what-order" tabindex="-1">OQ-1 — Which languages ship in v2.0, and in what order? <a class="header-anchor" href="#oq-1-—-which-languages-ship-in-v2-0-and-in-what-order" aria-label="Permalink to &quot;OQ-1 — Which languages ship in v2.0, and in what order?&quot;">​</a></h3><p><strong>Proposed priority order</strong> (optimises for: reach × STEM audience × implementation effort):</p><table tabindex="0"><thead><tr><th>Priority</th><th>Language</th><th>Script</th><th>Direction</th><th>Why</th></tr></thead><tbody><tr><td>1</td><td><strong>Spanish</strong></td><td>Latin</td><td>LTR</td><td>Largest new reach; Latin America + Spain; easy implementation; strong STEM community</td></tr><tr><td>2</td><td><strong>Mandarin (Simplified)</strong></td><td>CJK</td><td>LTR (vertical optional)</td><td>China is a Tier-1 Mars player; 1.1B speakers; CNSA audience</td></tr><tr><td>3</td><td><strong>French</strong></td><td>Latin</td><td>LTR</td><td>ESA working language; covers France + 29 Francophone countries</td></tr><tr><td>4</td><td><strong>Japanese</strong></td><td>CJK + Hiragana/Katakana</td><td>LTR</td><td>JAXA; high engagement; pays attention to science accuracy</td></tr><tr><td>5</td><td><strong>German</strong></td><td>Latin</td><td>LTR</td><td>DLR + strong STEM culture; ESA contributor</td></tr><tr><td>6</td><td><strong>Hindi</strong></td><td>Devanagari</td><td>LTR</td><td>ISRO; fastest-growing tech audience; 600M speakers</td></tr><tr><td>7</td><td><strong>Portuguese (BR)</strong></td><td>Latin</td><td>LTR</td><td>Brazil AEB; huge web gaming market</td></tr><tr><td>8</td><td><strong>Arabic</strong></td><td>Arabic</td><td><strong>RTL</strong></td><td>UAE space programme; growing STEM investment</td></tr><tr><td>9</td><td><strong>Korean</strong></td><td>Hangul</td><td>LTR</td><td>KARI; highly engaged tech audience</td></tr><tr><td>10</td><td><strong>Russian</strong></td><td>Cyrillic</td><td>LTR</td><td>Roscosmos heritage; large space-history community</td></tr><tr><td>11</td><td><strong>Italian</strong></td><td>Latin</td><td>LTR</td><td>ASI; ESA contributor</td></tr></tbody></table><p><strong>Alternatives to consider:</strong></p><ul><li><strong>Ship all 11 at once</strong> — maximises reach; risk is uneven quality across languages</li><li><strong>Two waves: Latin-script first, then non-Latin</strong> — reduces technical risk; delays CJK + RTL</li><li><strong>Community-translation model</strong> — open all slots, let contributors fill them; risk is quality control</li></ul><p><strong>Question for this RFC:</strong> Do we ship a defined list per-wave, or do we open a translation contribution model?</p><hr><h3 id="oq-2-—-how-do-we-handle-non-latin-scripts" tabindex="-1">OQ-2 — How do we handle non-Latin scripts? <a class="header-anchor" href="#oq-2-—-how-do-we-handle-non-latin-scripts" aria-label="Permalink to &quot;OQ-2 — How do we handle non-Latin scripts?&quot;">​</a></h3><p>Three distinct technical problems:</p><p><strong>2a. CJK (Mandarin, Japanese, Korean)</strong></p><ul><li>Requires CJK-capable font. Current stack uses <code>&#39;Space Mono&#39;</code> for data and <code>&#39;Bebas Neue&#39;</code> for titles — neither covers CJK.</li><li>Options: <ul><li><strong>Load Noto Sans SC / Noto Sans JP / Noto Sans KR</strong> from Google Fonts per locale (adds ~500KB per font)</li><li><strong>Use system fonts with fallback stack</strong> — <code>font-family: &#39;Space Mono&#39;, &#39;Noto Sans SC&#39;, system-ui</code> — zero bundle cost, inconsistent rendering</li><li><strong>Single Noto Sans CJK variable font</strong> — covers all three CJK locales; ~2MB; load on demand</li></ul></li></ul><p><strong>2b. RTL (Arabic)</strong></p><ul><li>Requires <code>dir=&quot;rtl&quot;</code> on <code>&lt;html&gt;</code> or per-section</li><li>All flex/grid layouts need RTL mirroring (<code>margin-inline-start</code> vs <code>margin-left</code>)</li><li>The canvas (Three.js, 2D porkchop plot) is direction-neutral — only the UI chrome changes</li><li>Options: <ul><li><strong>CSS logical properties throughout</strong> — <code>margin-inline</code>, <code>padding-block</code>, etc. — correct approach but requires audit of all existing CSS</li><li><strong>RTL override stylesheet</strong> — a separate <code>rtl.css</code> that overrides directional rules — faster to ship, harder to maintain</li><li><strong>Defer Arabic</strong> until CSS logical properties audit is complete</li></ul></li></ul><p><strong>2c. Devanagari (Hindi)</strong></p><ul><li>Standard Latin fonts do not cover Devanagari.</li><li>Noto Sans Devanagari covers it; ~400KB.</li><li>Rendering complexity is lower than CJK; no direction issue.</li></ul><p><strong>Question for this RFC:</strong> Do we require CSS logical properties as a prerequisite for Arabic, or do we ship an RTL override stylesheet?</p><hr><h3 id="oq-3-—-what-is-the-translation-workflow" tabindex="-1">OQ-3 — What is the translation workflow? <a class="header-anchor" href="#oq-3-—-what-is-the-translation-workflow" aria-label="Permalink to &quot;OQ-3 — What is the translation workflow?&quot;">​</a></h3><p>The i18n architecture uses JSON locale files (one per language). The question is how those files get populated and QA&#39;d.</p><p><strong>Option A — Professional translation agency</strong></p><ul><li>Highest quality; most expensive</li><li>Suitable for v2.0 launch languages (Spanish, French at minimum)</li><li>Estimated cost: $0.10–0.20/word × ~2,000 strings = $200–$400 per language</li></ul><p><strong>Option B — Community / contributor model</strong></p><ul><li>Open a <code>translations/</code> folder in the repo</li><li>Contributors submit PRs for their language</li><li>Maintainers review for technical accuracy (especially physics terminology)</li><li>Risk: inconsistent quality; physics errors in translation can mislead learners</li></ul><p><strong>Option C — AI-assisted + native speaker review</strong></p><ul><li>Use an LLM to produce a first-pass translation</li><li>Native speaker (contributor or paid reviewer) reviews for naturalness and physics accuracy</li><li>Most scalable; quality depends on reviewer</li></ul><p><strong>Option D — Hybrid</strong></p><ul><li>Professional translation for Tier-1 languages (Spanish, French, Mandarin)</li><li>Community model for remaining languages</li><li>AI-assisted first pass to reduce translator effort</li></ul><p><strong>Question for this RFC:</strong> Which workflow do we adopt, and does it differ by language tier?</p><hr><h2 id="maintainer-decisions-—-may-2026" tabindex="-1">Maintainer decisions — May 2026 <a class="header-anchor" href="#maintainer-decisions-—-may-2026" aria-label="Permalink to &quot;Maintainer decisions — May 2026&quot;">​</a></h2><p>Recorded ahead of formal ADR closure (see &quot;Evidence needed to close&quot; below).</p><p><strong>OQ-1 — Language selection:</strong> Adopt the priority order proposed in this RFC verbatim (Spanish 1, Mandarin 2, French 3, Japanese 4, German 5, Hindi 6, Portuguese-BR 7, Arabic 8, Korean 9, Russian 10, Italian 11). v0.3.x ships <strong>Spanish only</strong>; remaining Wave 1 languages move to PLANNED but unscheduled. Wave 2 (CJK) and Wave 3 (RTL) gated on the OQ-2 follow-ups.</p><p><strong>OQ-2 — Script handling:</strong> Wave 1 needs <strong>no new font work</strong> — <code>Bebas Neue</code> + <code>Space Mono</code> + <code>Crimson Pro</code> already cover the Latin-script extended characters needed for <code>es</code>/<code>fr</code>/<code>de</code>/<code>pt</code>/<code>it</code>. CJK font choice and RTL CSS-logical-properties audit are explicitly <strong>deferred</strong> to follow-up ADRs scheduled with their respective waves; not blocking v0.3.x.</p><p><strong>OQ-3 — Translation workflow:</strong> <strong>LLM-only first-pass translation, no native-speaker review</strong> for v0.3.x. Quality risk on physics terminology accuracy and idiomatic naturalness is accepted. Re-evaluation triggers: first user-reported translation issue, or first contributor offering native-speaker review for a given language. Formalised in ADR-033 once written.</p><p>These decisions close the RFC into ADR-031 (language list + waves), ADR-032 (font/script strategy — Wave 1 scope), and ADR-033 (workflow). RFC moves to <strong>Closed</strong> when those three ADRs land.</p><hr><h2 id="what-is-not-in-scope-for-this-rfc" tabindex="-1">What is NOT in scope for this RFC <a class="header-anchor" href="#what-is-not-in-scope-for-this-rfc" aria-label="Permalink to &quot;What is NOT in scope for this RFC&quot;">​</a></h2><ul><li>Changes to the i18n architecture (already locked in ADR-017)</li><li>Translation of the codebase itself (comments, variable names remain in English)</li><li>Localisation of units (km vs miles — a separate concern, may warrant its own ADR)</li><li>RTL support for the canvas / Three.js scenes (canvas is direction-neutral)</li><li>Locale-specific mission data (all missions use the same data regardless of locale)</li></ul><hr><h2 id="evidence-needed-to-close" tabindex="-1">Evidence needed to close <a class="header-anchor" href="#evidence-needed-to-close" aria-label="Permalink to &quot;Evidence needed to close&quot;">​</a></h2><p>This RFC closes when the following are answered and documented in ADRs:</p><table tabindex="0"><thead><tr><th>Question</th><th>Evidence needed</th><th>Closes into</th></tr></thead><tbody><tr><td>OQ-1: Language list + wave structure</td><td>Decision on list and phasing</td><td>ADR-0xx</td></tr><tr><td>OQ-2: Font strategy for CJK + RTL</td><td>Technical spike on font loading; CSS logical properties audit</td><td>ADR-0xx</td></tr><tr><td>OQ-3: Translation workflow</td><td>Decision on workflow per tier</td><td>ADR-0xx</td></tr></tbody></table><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><table tabindex="0"><thead><tr><th>What</th><th>Where</th></tr></thead><tbody><tr><td>i18n architecture decision</td><td><code>docs/adr/ADR-017.md</code></td></tr><tr><td>Accessibility RFC (a11y patterns relevant to i18n)</td><td><code>docs/rfc/RFC-005.md</code></td></tr><tr><td>v1.0 scope (i18n deferred)</td><td><code>docs/prd/PRD-006.md §deferred</code></td></tr><tr><td>ROADMAP</td><td><code>ROADMAP.md</code></td></tr></tbody></table>',66)])])}const u=e(o,[["render",i]]);export{p as __pageData,u as default};
